from flask import Flask, request, redirect, url_for, session, render_template
import os
from itsdangerous import URLSafeTimedSerializer

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Dummy user data for demonstration purposes
users = {
    "user1": {"password": "securepassword", "mfa_code": "123456"}
}

serializer = URLSafeTimedSerializer(app.secret_key)

def generate_mfa_token(user_id):
    return serializer.dumps(user_id, salt='mfa-salt')

def verify_mfa_token(token):
    try:
        user_id = serializer.loads(token, salt='mfa-salt', max_age=300)
        return user_id
    except:
        return None

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        
        if username in users and users[username]['password'] == password:
            session['user_id'] = username
            mfa_token = generate_mfa_token(username)
            return redirect(url_for('verify_mfa', token=mfa_token))
        else:
            return "Invalid username or password", 401
    
    return '''
        <form method="post">
            Username: <input type="text" name="username"><br>
            Password: <input type="password" name="password"><br>
            <input type="submit" value="Login">
        </form>
    '''

@app.route('/verify-mfa')
def verify_mfa():
    token = request.args.get('token')
    user_id = verify_mfa_token(token)
    
    if not user_id:
        return "Invalid MFA Token", 401
    
    session['mfa_verified'] = True
    return "MFA Verified. You can now access protected resources."

@app.route('/protected')
def protected():
    if 'user_id' in session and 'mfa_verified' in session:
        return f"Welcome, {session['user_id']}! This is a protected resource."
    else:
        return redirect(url_for('login'))

if __name__ == '__main__':
    app.run(debug=True)